fn has_task_definition_in_run_inner(
    loader: &L,
    workspace: &PackageName,
    task_name: &TaskName<'static>,
    task_id: &TaskId,
    visited: &mut HashSet<PackageName>,
) -> Result<TaskDefinitionResult, BuilderError> {
    // Avoid infinite loops from cyclic extends
    if visited.contains(workspace) {
        return Ok(TaskDefinitionResult::not_found());
    }
    visited.insert(workspace.clone());

    let turbo_json = loader.load(workspace).map_or_else(
        |err| {
            if err.is_no_turbo_json() && !matches!(workspace, PackageName::Root) {
                Ok(None)
            } else {
                Err(err)
            }
        },
        |turbo_json| Ok(Some(turbo_json)),
    )?;

    let Some(turbo_json) = turbo_json else {
        // If there was no turbo.json in the workspace, fallback to the root turbo.json
        return Self::has_task_definition_in_run_inner(
            loader,
            &PackageName::Root,
            task_name,
            task_id,
            visited,
        );
    };

    let task_id_as_name = task_id.as_task_name();

    // Helper to check task definition status based on extends configuration
    let check_task_def = |task_def: &RawTaskDefinition| -> TaskDefinitionResult {
        let has_extends_false = task_def
            .extends
            .as_ref()
            .map(|e| !*e.as_inner())
            .unwrap_or(false);

        if has_extends_false && !task_def.has_config_beyond_extends() {
            // Task is explicitly excluded via `extends: false` with no config
            TaskDefinitionResult::excluded()
        } else {
            // Task exists (either with `extends: false` + config, or normal definition)
            TaskDefinitionResult::found()
        }
    };

    // Check if this package's turbo.json has the task defined under various key
    // formats
    let base_task_name = TaskName::from(task_name.task());
    let check_base_task = matches!(workspace, PackageName::Root)
        || workspace == &PackageName::from(task_id.package());

    // Try task keys in order of specificity: task_id, task_name, base_task_name
    let task_def = turbo_json
        .tasks
        .get(&task_id_as_name)
        .or_else(|| turbo_json.tasks.get(task_name))
        .or_else(|| {
            if check_base_task {
                turbo_json.tasks.get(&base_task_name)
            } else {
                None
            }
        });

    if let Some(task_def) = task_def {
        return Ok(check_task_def(task_def));
    }

    // Check the extends chain for the task definition
    // Track if any package in the chain excluded this task
    for extend in turbo_json.extends.as_inner().iter() {
        let extend_package = PackageName::from(extend.as_str());
        let result = Self::has_task_definition_in_run_inner(
            loader,
            &extend_package,
            task_name,
            task_id,
            visited,
        )?;
        // If any package in the chain excluded this task, propagate that exclusion
        if result.is_excluded() {
            return Ok(TaskDefinitionResult::excluded());
        }
        if result.has_definition() {
            return Ok(TaskDefinitionResult::found());
        }
    }

    // This fallback only applies when there's no explicit `extends` field.
    // If `extends` is present (even if it only contains non-root packages),
    // we don't implicitly fall back to root since the validator ensures
    // the extends chain will eventually reach root.
    if turbo_json.extends.is_empty() && !matches!(workspace, PackageName::Root) {
        return Self::has_task_definition_in_run_inner(
            loader,
            &PackageName::Root,
            task_name,
            task_id,
            visited,
        );
    }

    Ok(TaskDefinitionResult::not_found())
}

fn task_definition(&self, task_id: &TaskId<'static>) -> Result<&TaskDefinition, Error> {
    self.engine
        .task_definition(task_id)
        .ok_or_else(|| Error::MissingTask(task_id.clone().into_owned()))
}

fn from_processed(
    processed: ProcessedTaskDefinition,
    path_to_repo_root: &RelativeUnixPath,
) -> Result<TaskDefinition, BuilderError> {
    // Convert outputs with turbo_root resolution
    let outputs = processed
        .outputs
        .map(|outputs| task_outputs_from_processed(outputs, path_to_repo_root))
        .transpose()?
        .unwrap_or_default();

    let cache = processed.cache.is_none_or(|c| c.into_inner());
    let interactive = processed
        .interactive
        .as_ref()
        .map(|value| value.value)
        .unwrap_or_default();

    if let Some(interactive) = &processed.interactive {
        let (span, text) = interactive.span_and_text("turbo.json");
        if cache && interactive.value {
            return Err(BuilderError::TurboJson(
                turborepo_turbo_json::Error::InteractiveNoCacheable { span, text },
            ));
        }
    }

    let persistent = *processed.persistent.unwrap_or_default();
    let interruptible = processed.interruptible.unwrap_or_default();
    if *interruptible && !persistent {
        let (span, text) = interruptible.span_and_text("turbo.json");
        return Err(BuilderError::TurboJson(
            turborepo_turbo_json::Error::InterruptibleButNotPersistent { span, text },
        ));
    }

    let mut topological_dependencies: Vec<Spanned<TaskName>> = Vec::new();
    let mut task_dependencies: Vec<Spanned<TaskName>> = Vec::new();
    if let Some(depends_on) = processed.depends_on {
        for dependency in depends_on.deps {
            let (dependency, depspan) = dependency.split();
            let dependency: String = dependency.into();
            if let Some(topo_dependency) =
                dependency.strip_prefix(TOPOLOGICAL_PIPELINE_DELIMITER)
            {
                topological_dependencies.push(depspan.to(topo_dependency.to_string().into()));
            } else {
                task_dependencies.push(depspan.to(dependency.into()));
            }
        }
    }

    task_dependencies.sort_by(|a, b| a.value.cmp(&b.value));
    topological_dependencies.sort_by(|a, b| a.value.cmp(&b.value));

    let env = processed.env.map(|env| env.vars).unwrap_or_default();

    // Convert inputs with turbo_root resolution
    let inputs = processed
        .inputs
        .map(|inputs| TaskInputs::from_processed(inputs, path_to_repo_root))
        .unwrap_or_default();

    let pass_through_env = processed.pass_through_env.map(|env| env.vars);

    let with = processed.with.map(|with_tasks| with_tasks.tasks);

    Ok(TaskDefinition {
        outputs,
        cache,
        topological_dependencies,
        task_dependencies,
        env,
        inputs,
        pass_through_env,
        output_logs: *processed.output_logs.unwrap_or_default(),
        persistent,
        interruptible: *interruptible,
        interactive,
        env_mode: processed.env_mode.map(|mode| *mode.as_inner()),
        with,
    })
}

pub fn add_definition(&mut self, task_id: TaskId<'static>, definition: T) -> Option<T> {
    if definition.persistent() && !definition.interruptible() {
        self.has_non_interruptible_tasks = true;
    }
    self.task_definitions.insert(task_id, definition)
}

fn test_run_summary_enable_matrix() {
    let tempdir = tempfile::tempdir().unwrap();
    setup::setup_integration_test(tempdir.path(), "basic_monorepo", "npm@10.5.0", true).unwrap();

    struct Case {
        env_val: Option<&'static str>,
        flag: Option<&'static str>,
        expect_summary: bool,
    }

    let cases = vec![
        // env=true
        Case {
            env_val: Some("true"),
            flag: None,
            expect_summary: true,
        },
        Case {
            env_val: Some("true"),
            flag: Some("--summarize=true"),
            expect_summary: true,
        },
        Case {
            env_val: Some("true"),
            flag: Some("--summarize=false"),
            expect_summary: false,
        },
        Case {
            env_val: Some("true"),
            flag: Some("--summarize"),
            expect_summary: true,
        },
        // env=false
        Case {
            env_val: Some("false"),
            flag: None,
            expect_summary: false,
        },
        Case {
            env_val: Some("false"),
            flag: Some("--summarize=true"),
            expect_summary: true,
        },
        Case {
            env_val: Some("false"),
            flag: Some("--summarize=false"),
            expect_summary: false,
        },
        Case {
            env_val: Some("false"),
            flag: Some("--summarize"),
            expect_summary: true,
        },
        // env missing
        Case {
            env_val: None,
            flag: None,
            expect_summary: false,
        },
        Case {
            env_val: None,
            flag: Some("--summarize=true"),
            expect_summary: true,
        },
        Case {
            env_val: None,
            flag: Some("--summarize=false"),
            expect_summary: false,
        },
        Case {
            env_val: None,
            flag: Some("--summarize"),
            expect_summary: true,
        },
    ];

    for (i, case) in cases.iter().enumerate() {
        let _ = fs::remove_dir_all(tempdir.path().join(".turbo/runs"));

        let mut args = vec!["run", "build"];
        if let Some(flag) = case.flag {
            args.push(flag);
        }

        let env: Vec<(&str, &str)> = match case.env_val {
            Some(val) => vec![("TURBO_RUN_SUMMARY", val)],
            None => vec![],
        };

        run_turbo_with_env(tempdir.path(), &args, &env);

        let has_summary = tempdir.path().join(".turbo/runs").exists()
            && fs::read_dir(tempdir.path().join(".turbo/runs"))
                .map(|d| {
                    d.filter_map(|e| e.ok())
                        .any(|e| e.file_name().to_string_lossy().ends_with(".json"))
                })
                .unwrap_or(false);

        assert_eq!(
            has_summary, case.expect_summary,
            "case {i}: env={:?} flag={:?} expected summary={} got={}",
            case.env_val, case.flag, case.expect_summary, has_summary
        );
    }
}

pub fn has_definition(&self) -> bool {
    self.has_definition
}
